import React, { useState, useEffect } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Modal,
  Box,
  Typography,
  Select,
  MenuItem,
  InputLabel,
  FormControl,
  Stack,
  Menu,
  Checkbox,
  ListItemText,
  IconButton,
} from '@mui/material';
import ProductTypeForm from './ProductTypeForm';
import { getProductTypes, deleteProductType } from '../services/api';

const filterOptions = ['Active Product Types', 'All Product Types'];
const allColumns = [
  { field: 'id', label: 'id' },
  { field: 'display_name', label: 'Display Name' },
  { field: 'api_name', label: 'API Name' },
  { field: 'asset_type', label: 'Asset Type' },
  { field: 'asset_category_type', label: 'Asset Category' },
  { field: 'description', label: 'Description' },
];

const ProductTypeTable = () => {
  const [productTypes, setProductTypes] = useState([]);
  const [open, setOpen] = useState(false);
  const [editing, setEditing] = useState(null);
  const [activeFilter, setActiveFilter] = useState(filterOptions[0]);
  const [actionAnchorEl, setActionAnchorEl] = useState(null);
  const [actionRow, setActionRow] = useState(null);
  const [columnsAnchorEl, setColumnsAnchorEl] = useState(null);
  const [visibleColumns, setVisibleColumns] = useState([
    'display_name',
    'api_name',
    'asset_type',
    'asset_category_type',
    'description',
  ]);

  useEffect(() => {
    fetchProductTypes();
  }, []);

  const fetchProductTypes = async () => {
    try {
      const response = await getProductTypes();
      setProductTypes(response.data);
    } catch (error) {
      console.error('Error fetching product types:', error);
    }
  };

  const handleOpen = (item = null) => {
    setEditing(item);
    setOpen(true);
  };

  const handleClose = () => {
    setOpen(false);
    setEditing(null);
  };

  const handleSave = () => {
    fetchProductTypes();
    handleClose();
  };

  const handleDelete = async (id) => {
    try {
      await deleteProductType(id);
      fetchProductTypes();
    } catch (error) {
      console.error('Error deleting product type:', error);
    }
  };

  const handleClearFilters = () => {
    setActiveFilter(filterOptions[0]);
  };

  return (
    <Box>
      <Paper sx={{ p: 2, mb: 2, bgcolor: 'white' }} elevation={1}>
        <Stack direction={{ xs: 'column', md: 'row' }} alignItems="center" justifyContent="space-between" spacing={2}>
          <FormControl sx={{ minWidth: 260 }}>
            <InputLabel id="active-filter-label">Active Product Types</InputLabel>
            <Select
              labelId="active-filter-label"
              value={activeFilter}
              label="Active Product Types"
              onChange={(e) => setActiveFilter(e.target.value)}
            >
              {filterOptions.map((option) => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <Stack direction="row" spacing={1} sx={{ ml: 'auto' }}>
            <Button variant="outlined" size="small" onClick={handleClearFilters}>
              Clear All Filters
            </Button>
            <Button variant="outlined" size="small" onClick={(e) => setColumnsAnchorEl(e.currentTarget)}>
              Select Columns
            </Button>
            <Button variant="contained" size="small" onClick={() => handleOpen()}>
              New
            </Button>
          </Stack>
        </Stack>
      </Paper>

      <Menu anchorEl={columnsAnchorEl} open={Boolean(columnsAnchorEl)} onClose={() => setColumnsAnchorEl(null)}>
        {allColumns.map((column) => (
          <MenuItem key={column.field} onClick={() => setVisibleColumns((prev) =>
            prev.includes(column.field)
              ? prev.filter((value) => value !== column.field)
              : [...prev, column.field],
          )}
          >
            <Checkbox checked={visibleColumns.includes(column.field)} />
            <ListItemText primary={column.label} />
          </MenuItem>
        ))}
      </Menu>

      <TableContainer component={Paper} sx={{ p: 1, bgcolor: 'white' }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>
                <Typography fontWeight={600}>Display Name</Typography>
              </TableCell>
              <TableCell>
                <Typography fontWeight={600}>API Name</Typography>
              </TableCell>
              <TableCell>
                <Typography fontWeight={600}>Asset Type</Typography>
              </TableCell>
              <TableCell>
                <Typography fontWeight={600}>Asset Category</Typography>
              </TableCell>
              <TableCell>
                <Typography fontWeight={600}>Description</Typography>
              </TableCell>
              <TableCell align="right">
                <Typography fontWeight={600}>Actions</Typography>
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {productTypes.map((item) => (
              <TableRow key={item.id} hover>
                <TableCell>{item.display_name}</TableCell>
                <TableCell>{item.api_name}</TableCell>
                <TableCell>{item.asset_type}</TableCell>
                <TableCell>{item.asset_category_type}</TableCell>
                <TableCell>{item.description}</TableCell>
                <TableCell align="right">
                  <Stack direction="row" spacing={1} justifyContent="flex-end">
                    <Button size="small" variant="outlined" onClick={() => handleOpen(item)}>
                      Edit
                    </Button>
                    <Button size="small" variant="outlined" color="error" onClick={() => handleDelete(item.id)}>
                      Delete
                    </Button>
                  </Stack>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>

      <Modal open={open} onClose={handleClose}>
        <Box
          sx={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: { xs: '92%', sm: 560 },
            bgcolor: 'background.paper',
            boxShadow: 24,
            p: 4,
            borderRadius: 2,
          }}
        >
          <Typography variant="h6" component="h2" sx={{ mb: 2 }}>
            {editing ? 'Edit Product Type' : 'New Product Type'}
          </Typography>
          <ProductTypeForm
            editing={editing}
            onSave={handleSave}
            onClose={handleClose}
            productTypes={productTypes}
          />
        </Box>
      </Modal>
    </Box>
  );
};

export default ProductTypeTable;
